const input = $input.first().json;

const tickers = input["Ticker"] || [];
const prices = input["Price"] || [];
const changes = input["Change Percentage"] || [];
const summaries = input["Summary"] || [];

let htmlEmail = `
<div style="font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; max-width: 650px; margin: auto; background-color: #f9f9f9; padding: 20px;">
  <div style="background-color: #1a2a3a; padding: 30px; text-align: center; border-radius: 12px 12px 0 0; color: #ffffff;">
    <h1 style="margin: 0; font-size: 26px; font-weight: 600;">Morning Brief: Portfölj 📈</h1>
    <p style="margin: 5px 0 0; opacity: 0.8; font-size: 14px;">${new Date().toISOString().split('T')[0]}</p>
  </div>
  <div style="background-color: #ffffff; border: 1px solid #e0e6ed; border-top: none; border-radius: 0 0 12px 12px; overflow: hidden;">
`;

for (let i = 0; i < tickers.length; i++) {
    const ticker = tickers[i] || "Okänt innehav";
    const price = prices[i] || "-";
    const change = (changes[i] !== undefined) ? changes[i] : "0%";
    const aiSummary = summaries[i] || "Ingen analys tillgänglig för tillfället.";

    const isPositive = !String(change).includes('-');
    const color = isPositive ? '#27ae60' : '#e74c3c';
    const arrow = isPositive ? '▲' : '▼';

    htmlEmail += `
    <div style="padding: 25px; border-bottom: 1px solid #f0f4f8;">
      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;">
        <span style="font-size: 20px; font-weight: 800; color: #1a2a3a;">${ticker}</span>
        <div style="background-color: ${color}15; color: ${color}; padding: 6px 12px; border-radius: 20px; font-weight: 700; font-size: 14px;">
          ${arrow} ${price} (${change}${typeof change === 'number' ? '%' : ''})
        </div>
      </div>

      <div style="font-size: 15px; line-height: 1.7; color: #444;">
        ${aiSummary} 
      </div>
    </div>
    `;
}

if (tickers.length === 0) {
    htmlEmail += `<div style="padding: 40px; text-align: center; color: #7f8c8d;">No data was found for your holdings today.</div>`;
}

htmlEmail += `
    <div style="padding: 20px; text-align: center; font-size: 12px; color: #95a5a6; background-color: #fdfdfd;">
      Genererat via n8n & AI • Finansiell data från Google Finance
    </div>
  </div>
</div>
`;

return [{ json: { htmlBody: htmlEmail, subject: `Börsrapport: ${new Date().toISOString().split('T')[0]}` } }];

const newsItems = $json.web?.results || [];
const currentTicker = $('Loop over stocks').item.json.Ticker || "Unknown";

let newsText = "";

if (newsItems.length > 0) {
    newsText = newsItems.map((news, index) => {
        const title = news.title || "No Title";
        const snippet = news.description || news.snippet || "No Description";
        const link = news.url || news.link || "#";
        const source = news.profile?.name || news.meta_url?.hostname || "Unknown Source";

        return `NEWS ${index + 1}:\nSource: ${source}\nTitle: ${title}\nInfo: ${snippet}\nLink: ${link}\n-------------------`;
    }).join('\n\n');
} else {
    newsText = "No news found for this ticker in the last 24 hours.";
}

return {
    ticker: currentTicker, 
    formattedNews: newsText
};
